def validate(args, output):
    n, edges = args[0], args[1]
    if not isinstance(output, list) or not output:
        return False
    rows = len(output)
    cols = None
    seen = set()
    for row in output:
        if not isinstance(row, list):
            return False
        if cols is None:
            cols = len(row)
        elif len(row) != cols:
            return False
        for v in row:
            if not isinstance(v, int) or isinstance(v, bool) or v < 0 or v >= n or v in seen:
                return False
            seen.add(v)
    if not cols or rows * cols != n or len(seen) != n:
        return False
    grid_edges = set()
    for r in range(rows):
        for c in range(cols):
            if c + 1 < cols:
                a, b = output[r][c], output[r][c + 1]
                grid_edges.add((min(a, b), max(a, b)))
            if r + 1 < rows:
                a, b = output[r][c], output[r + 1][c]
                grid_edges.add((min(a, b), max(a, b)))
    input_edges = {(min(u, v), max(u, v)) for u, v in edges}
    return grid_edges == input_edges

