function validate(args, output) {
    const n = args[0], edges = args[1];
    if (!Array.isArray(output) || output.length === 0) return false;
    const rows = output.length;
    let cols = null;
    const seen = new Set();
    for (const row of output) {
        if (!Array.isArray(row)) return false;
        if (cols === null) cols = row.length;
        else if (row.length !== cols) return false;
        for (const v of row) {
            if (typeof v !== 'number' || !Number.isInteger(v) || v < 0 || v >= n || seen.has(v)) return false;
            seen.add(v);
        }
    }
    if (!cols || rows * cols !== n || seen.size !== n) return false;
    const key = (a, b) => (a < b ? a + ',' + b : b + ',' + a);
    const gridEdges = new Set();
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            if (c + 1 < cols) gridEdges.add(key(output[r][c], output[r][c + 1]));
            if (r + 1 < rows) gridEdges.add(key(output[r][c], output[r + 1][c]));
        }
    }
    const inputEdges = new Set();
    for (const [u, v] of edges) inputEdges.add(key(u, v));
    if (gridEdges.size !== inputEdges.size) return false;
    for (const k of gridEdges) if (!inputEdges.has(k)) return false;
    return true;
}

