var constructGridLayout = function(n, edges) {
    if (n === 1) return [[0]];
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }
    const deg = adj.map(a => a.length);
    const maxDeg = deg.reduce((m, d) => Math.max(m, d), 0);
    const hasDeg1 = deg.some(d => d === 1);

    if (maxDeg <= 2 && hasDeg1) {
        let start = -1;
        for (let i = 0; i < n; i++) { if (deg[i] === 1) { start = i; break; } }
        const path = [start];
        let prev = null, cur = start;
        while (path.length < n) {
            const nxt = adj[cur].find(v => v !== prev);
            path.push(nxt);
            prev = cur;
            cur = nxt;
        }
        return [path];
    }

    let corner = -1;
    for (let i = 0; i < n; i++) { if (deg[i] === 2) { corner = i; break; } }
    const sortedNbrs = [...adj[corner]].sort((x, y) => x - y);
    const a = sortedNbrs[0], b = sortedNbrs[1];

    const row0 = [corner, a];
    const row1 = [b, null];
    let prev0 = corner, prevRef = b, cur0 = a;
    while (true) {
        const curSet = new Set(adj[cur0]);
        const common = adj[prevRef].filter(v => curSet.has(v) && v !== prev0);
        const below = common.length > 0 ? common[0] : null;
        row1[row1.length - 1] = below;
        const exclude = new Set([prev0]);
        if (below !== null) exclude.add(below);
        const nxtCandidates = adj[cur0].filter(v => !exclude.has(v));
        if (nxtCandidates.length === 0) break;
        const nxt = nxtCandidates[0];
        row0.push(nxt);
        row1.push(null);
        prev0 = cur0; prevRef = below; cur0 = nxt;
    }

    const cols = row0.length;
    const grid = [row0, row1];
    while (grid.length * cols < n) {
        const prevRow = grid[grid.length - 2];
        const lastRow = grid[grid.length - 1];
        const nextRow = [];
        let ok = true;
        for (let j = 0; j < cols; j++) {
            const exclude = new Set([prevRow[j]]);
            if (j > 0) exclude.add(lastRow[j - 1]);
            if (j < cols - 1) exclude.add(lastRow[j + 1]);
            const cands = adj[lastRow[j]].filter(v => !exclude.has(v));
            if (cands.length === 0) { ok = false; break; }
            nextRow.push(cands[0]);
        }
        if (!ok) break;
        grid.push(nextRow);
    }
    return grid;
};
